  ('disabled-0a2fc18c-moex-00154', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '消費者A的無異曲線圖如下，圖中箭號代表效用增加的方向。下列敘述何 者較貼切描寫出消費者A的偏好？ 肉類 蔬食', '["消費者A偏好食用肉類，吃蔬食會感到不舒服", "消費者A偏好食用蔬食，吃肉類會感到不舒服", "消費者A偏好食用肉類，吃蔬食覺得食之無味", "消費者A偏好食用蔬食，吃肉類覺得食之無味"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00155', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '如果一家廠商的生產技術呈現規模報酬遞增，下列敘述何者正確？', '["長期平均成本遞減", "長期平均成本遞增", "長期平均成本不變", "長期平均成本先減後增"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00156', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '一家競爭廠商用資本和勞動兩種要素生產它的產品。在目前的產量之下， 資本的邊際產出MP = 50，勞動的邊際產出MP = 30。資本和勞動的固 K L 定市場價格分別是r = 20和w = 5。在不增加成本的前提下，如何重新配 置要素方能提升產量？', '["增加資本僱用，減少勞動僱用", "減少資本僱用，增加勞動僱用", "同時減少資本和勞動的僱用", "同時增加資本和勞動的僱用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00157', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '當長期平均成本曲線隨產量增加而遞減時，則該廠商有：', '["規模不經濟", "規模經濟", "外部不經濟", "外部經濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00158', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '一家自然獨占廠商面對的需求線是P=102Q，其中P和Q分別代表市場的 價格與需求量。如果這家廠商的平均總成本函數是ATC(Q)=2+(1600/Q)， 當政府採用邊際成本訂價法管制這家廠商時，這家廠商的產量是多少？', '["50", "51", "100", "102"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00159', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '一個獨占廠商面對一條負斜率的線性需求線，它的邊際成本為一條正斜率 的直線，當產量為200時，邊際收入為10元，邊際成本也是10元，對應 的需求線上的價格為 30 元，產量為 300 時，邊際成本線與需求線相交於 20元，此獨占廠商在均衡時所造成的無謂損失為何？', '["4,000元", "3,000元", "1,000元", "2,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00160', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '有關後彎的勞動供給曲線之敘述，下列何者錯誤？', '["造成此一現象的原因在於當工資率變動的替代效果超過所得效果所致", "此一性質可用來說明當工資率高到某種程度時人們的工作意願會降低 的現象", "後彎的勞動供給曲線表示同一種工時對應兩個不同的工資水準", "不滿足供給法則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00161', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '有關廠商的要素僱用之敘述，下列何者正確？', '["最適的勞動僱用量應該使得勞動的邊際生產收益等於工資水準", "最適的要素僱用應該使得各種生產要素的邊際產出除以其要素價格的 比值皆相等", "當勞動的邊際生產收益（MRP ）低於其要素價格時應該要減少勞動的僱 L 用水準", "最適的要素僱用應該使得各種要素僱用的邊際生產收益（MRP）皆相等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
