  ('disabled-0a2fc18c-moex-00163', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '有關勞動需求的敘述，下列何者錯誤？', '["對廠商而言，勞動需求是引伸性的需求", "勞動需求曲線通常是負斜率", "當總工資占總成本的比例越高時，廠商的勞動需求彈性越大", "在生產的過程中，當機器設備與勞動力越容易互相替代時，廠商的勞動 需求彈性越小"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL)
